mapper.sql:
SELECT
ID,
ORDER_TYPE,
CASE WHEN ORDER_TYPE = '1' THEN '疏港' WHEN ORDER_TYPE = '3' THEN '装船' END ORDER_TYPE_NAME,
CUSTOMER_ID,
CUSTOMER_NAME,
STATUS,
CASE WHEN STATUS = '0' THEN '待审核' WHEN STATUS = '1' THEN '已审核' END STATUS_NAME,
CREATE_BY,
CREATE_BY_NAME,
CREATE_TIME,
UPDATE_BY,
UPDATE_BY_NAME,
UPDATE_TIME,
APPROVED_BY,
APPROVED_BY_NAME,
APPROVED_TIME,
SHIPVOYAGE_ID,
SHIPVOYAGE_ITEM_ID,
SHIP_NAME,
VOYAGE
FROM
T_BUS_ORDER


        and ID = #{id}


        and ORDER_TYPE = #{orderType}


        and CUSTOMER_ID = #{customerId}


        and CUSTOMER_NAME = #{customerName}


        and STATUS = #{status}


        and APPROVED_BY = #{approvedBy}


        and APPROVED_BY_NAME = #{approvedByName}


        and APPROVED_TIME = #{approvedTime}


        and SHIPVOYAGE_ID = #{shipvoyageId}


        and SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}


        and SHIP_NAME = #{shipName}


        and VOYAGE = #{voyage}

